-- Modify "finance_facts" table
ALTER TABLE "finance_facts" ADD CONSTRAINT "finance_facts_cancel_audit_bundle" CHECK ((((status)::text = 'CANCELLED'::text) AND (cancel_audit_version = 0) AND (cancelled_at IS NULL) AND (cancelled_by IS NULL) AND (cancel_reason IS NULL)) OR (((status)::text = 'CANCELLED'::text) AND (cancel_audit_version = 1) AND (cancelled_at IS NOT NULL) AND (cancelled_by IS NOT NULL) AND (cancel_reason IS NOT NULL) AND ((length(TRIM(BOTH FROM cancel_reason)) >= 1) AND (length(TRIM(BOTH FROM cancel_reason)) <= 255))) OR (((status)::text <> 'CANCELLED'::text) AND (cancelled_at IS NULL) AND (cancelled_by IS NULL) AND (cancel_reason IS NULL))), ADD CONSTRAINT "finance_facts_cancel_audit_version" CHECK (cancel_audit_version = ANY (ARRAY[(0)::bigint, (1)::bigint])), ADD COLUMN "cancelled_at" timestamptz NULL, ADD COLUMN "cancel_reason" character varying NULL, ADD COLUMN "cancel_audit_version" bigint NOT NULL DEFAULT 0, ADD COLUMN "cancelled_by" bigint NULL, ADD CONSTRAINT "finance_facts_admin_users_canceller" FOREIGN KEY ("cancelled_by") REFERENCES "admin_users" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION;
